import scala.sys.process._
import scala.util.{Try, Success, Failure}

case class CommandRequest(command: String, arguments: List[String])
case class CommandResult(exitCode: Int, stdout: String, stderr: String)

object SafeCommandExecutor {

  // Allowlist of permitted commands for system administration
  private val allowedCommands: Set[String] = Set(
    "df",
    "free",
    "uptime",
    "whoami",
    "hostname",
    "date",
    "ps",
    "top",
    "systemctl",
    "journalctl",
    "ls",
    "cat",
    "grep",
    "netstat",
    "ss",
    "ip",
    "ping",
    "traceroute",
    "dig",
    "nslookup"
  )

  // Blocklist of dangerous argument patterns
  private val dangerousPatterns: List[String] = List(
    ";", "&&", "||", "|", "`", "$(", "${", ">", "<", "\n", "\r", "&"
  )

  def validateCommand(request: CommandRequest): Either[String, CommandRequest] = {
    val baseCommand = request.command.trim.toLowerCase

    if (!allowedCommands.contains(baseCommand)) {
      Left(s"Command '$baseCommand' is not in the allowlist. Allowed commands: ${allowedCommands.mkString(", ")}")
    } else if (request.arguments.exists(arg => dangerousPatterns.exists(arg.contains))) {
      Left(s"Arguments contain disallowed characters/patterns: ${dangerousPatterns.mkString(", ")}")
    } else if (request.arguments.exists(_.contains(".."))) {
      Left("Path traversal patterns are not allowed in arguments")
    } else {
      Right(request)
    }
  }

  /**
   * Executes a command SAFELY by passing arguments as a sequence (not via shell interpolation).
   * This uses ProcessBuilder semantics where each argument is a separate token,
   * preventing shell injection entirely.
   */
  def executeCommand(request: CommandRequest): Either[String, CommandResult] = {
    validateCommand(request).flatMap { validatedRequest =>
      Try {
        val stdoutBuilder = new StringBuilder
        val stderrBuilder = new StringBuilder

        // SAFE: Using Seq-based process construction — NOT shell interpolation.
        // Each element is passed as a separate argument to execvp, so no shell parsing occurs.
        val cmdSeq: Seq[String] = validatedRequest.command +: validatedRequest.arguments

        val processLogger = ProcessLogger(
          line => stdoutBuilder.append(line).append("\n"),
          line => stderrBuilder.append(line).append("\n")
        )

        val exitCode = Process(cmdSeq).!(processLogger)

        CommandResult(
          exitCode = exitCode,
          stdout = stdoutBuilder.toString().trim,
          stderr = stderrBuilder.toString().trim
        )
      } match {
        case Success(result) => Right(result)
        case Failure(ex) => Left(s"Command execution failed: ${ex.getMessage}")
      }
    }
  }
}

